spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 8000;
    var progressMs = t % duration;
    var seconds = progressMs / 1000;

    // Stop moving after 5 seconds to let the user digest the final values
    if (seconds > 5) {
      seconds = 5;
    }

    var roadY = H / 2 + 10;
    var startX = 35;
    var speed = 32; // pixels per second
    var carX = startX + speed * seconds;
    var distance = Math.round(speed * seconds);

    // Draw road
    ctx.beginPath();
    ctx.moveTo(15, roadY);
    ctx.lineTo(W - 15, roadY);
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 2;
    ctx.stroke();

    // Draw ticks on road at 0, 32, 64, 96, 128, 160
    ctx.fillStyle = '#6B7280';
    ctx.font = '8px monospace';
    ctx.textAlign = 'center';
    for (var i = 0; i <= 5; i++) {
      var tx = startX + speed * i;
      ctx.beginPath();
      ctx.moveTo(tx, roadY);
      ctx.lineTo(tx, roadY + 4);
      ctx.stroke();
      ctx.fillText(i * 32, tx, roadY + 12);
    }

    // Draw Car
    ctx.fillStyle = '#EF4444'; // Red car body
    ctx.fillRect(carX - 18, roadY - 14, 26, 10);
    ctx.fillRect(carX - 10, roadY - 20, 14, 7); // top cabin

    // Wheels
    ctx.fillStyle = '#000000';
    ctx.beginPath(); ctx.arc(carX - 12, roadY - 2, 3, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(carX + 2, roadY - 2, 3, 0, Math.PI * 2); ctx.fill();

    // Draw start line marker
    ctx.beginPath();
    ctx.moveTo(startX, roadY - 25);
    ctx.lineTo(startX, roadY);
    ctx.strokeStyle = 'rgba(239, 68, 68, 0.4)';
    ctx.lineWidth = 1;
    ctx.stroke();

    // Displays
    ctx.font = 'bold 12px monospace';
    ctx.textAlign = 'left';
    ctx.fillStyle = '#60A5FA';
    ctx.fillText('Time (t):     ' + seconds.toFixed(2) + ' s', 20, 30);
    ctx.fillStyle = '#10B981';
    ctx.fillText('Distance (d): ' + distance + ' m', 20, 48);
    ctx.fillStyle = '#F59E0B';
    ctx.fillText('Ratio (d / t): 32 m/s (Constant)', 20, 66);

    // Explanations
    ctx.textAlign = 'center';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('d = 32 × t', W / 2, H - 42);
    ctx.font = '11px -apple-system, sans-serif';
    ctx.fillStyle = '#9CA3AF';
    ctx.fillText('Double the time, double the distance. The speed is the constant k.', W / 2, H - 22);
  }
};
